import{_ as l,o as i,c as t,a2 as e}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1991年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1991年/核心总结.md","filePath":"01_letters/1991年/核心总结.md"}'),r={name:"01_letters/1991年/核心总结.md"};function o(h,a,d,n,u,s){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="_1991年巴菲特致股东信核心要点" tabindex="-1">1991年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1991年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1991年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长21亿美元（39.6%）</li><li>每股账面价值从$19增长至$6,437</li><li>27年复合增长率：23.7%</li><li>可口可乐和吉列贡献16亿美元增值</li></ul><hr><h2 id="双重收益到单一收益" tabindex="-1">双重收益到单一收益 <a class="header-anchor" href="#双重收益到单一收益" aria-label="Permalink to &quot;双重收益到单一收益&quot;">​</a></h2><h3 id="double-dip-vs-single-dip" tabindex="-1">Double Dip vs Single Dip <a class="header-anchor" href="#double-dip-vs-single-dip" aria-label="Permalink to &quot;Double Dip vs Single Dip&quot;">​</a></h3><ul><li>过去享受&quot;双重收益&quot;： <ul><li>公司盈利增长</li><li>估值修复</li></ul></li><li>未来只能获得&quot;单一收益&quot;：业务增长本身</li><li>可口可乐、吉列估值涨幅远超盈利涨幅</li></ul><h3 id="规模的诅咒" tabindex="-1">规模的诅咒 <a class="header-anchor" href="#规模的诅咒" aria-label="Permalink to &quot;规模的诅咒&quot;">​</a></h3><ul><li>净资产74亿美元</li><li>过去2000万赚100万就能贡献5%</li><li>现在3.7亿才能做到</li><li>机会自然减少</li></ul><hr><h2 id="透视盈利" tabindex="-1">透视盈利 <a class="header-anchor" href="#透视盈利" aria-label="Permalink to &quot;透视盈利&quot;">​</a></h2><h3 id="_1991年下降原因" tabindex="-1">1991年下降原因 <a class="header-anchor" href="#_1991年下降原因" aria-label="Permalink to &quot;1991年下降原因&quot;">​</a></h3><ol><li>媒体盈利下降</li><li>吉列优先股转普通股（减少报告收益3500万）</li><li>富国银行留存盈利为负（意外）</li><li>保险利润低于预期</li></ol><hr><h2 id="媒体行业变局" tabindex="-1">媒体行业变局 <a class="header-anchor" href="#媒体行业变局" aria-label="Permalink to &quot;媒体行业变局&quot;">​</a></h2><h3 id="经济特许经营权的定义" tabindex="-1">经济特许经营权的定义 <a class="header-anchor" href="#经济特许经营权的定义" aria-label="Permalink to &quot;经济特许经营权的定义&quot;">​</a></h3><ol><li>消费者需要或想要</li><li>消费者觉得没有替代品</li><li>价格不受管制</li></ol><h3 id="媒体特许经营权削弱" tabindex="-1">媒体特许经营权削弱 <a class="header-anchor" href="#媒体特许经营权削弱" aria-label="Permalink to &quot;媒体特许经营权削弱&quot;">​</a></h3><ul><li>广告娱乐选择增多</li><li>零售模式变化</li><li>广告市场碎片化</li></ul><h3 id="估值影响" tabindex="-1">估值影响 <a class="header-anchor" href="#估值影响" aria-label="Permalink to &quot;估值影响&quot;">​</a></h3><ul><li>过去预期：盈利每年6%增长，无需增量资本</li><li>现在预期：盈利围绕基准波动</li><li>同样的1000万盈利，估值从2500万降至1000万</li></ul><hr><h2 id="喜诗糖果二十年启示" tabindex="-1">喜诗糖果二十年启示 <a class="header-anchor" href="#喜诗糖果二十年启示" aria-label="Permalink to &quot;喜诗糖果二十年启示&quot;">​</a></h2><h3 id="收购背景" tabindex="-1">收购背景 <a class="header-anchor" href="#收购背景" aria-label="Permalink to &quot;收购背景&quot;">​</a></h3><ul><li>1972年以3000万美元收购（净资产700万）</li><li>20年累计税前利润4.2亿美元</li><li>仅投入增量资本1800万美元</li></ul><h3 id="关键数据" tabindex="-1">关键数据 <a class="header-anchor" href="#关键数据" aria-label="Permalink to &quot;关键数据&quot;">​</a></h3><ul><li>销售额：2900万→1.96亿美元</li><li>税前利润：420万→4240万</li><li>利润率：21.6%（创新高）</li></ul><h3 id="学到的教训" tabindex="-1">学到的教训 <a class="header-anchor" href="#学到的教训" aria-label="Permalink to &quot;学到的教训&quot;">​</a></h3><ul><li>理解经济特许经营权</li><li>如何评价特许经营权价值</li><li>后续很多投资得益于此</li></ul><hr><h2 id="h-h-brown收购" tabindex="-1">H.H. Brown收购 <a class="header-anchor" href="#h-h-brown收购" aria-label="Permalink to &quot;H.H. Brown收购&quot;">​</a></h2><h3 id="收购背景-1" tabindex="-1">收购背景 <a class="header-anchor" href="#收购背景-1" aria-label="Permalink to &quot;收购背景&quot;">​</a></h3><ul><li>1927年创立，62年历史</li><li>创始人女儿女婿Frank Rooney管理</li><li>美国鞋业面对进口竞争，但Brown表现出色</li></ul><h3 id="成功要素" tabindex="-1">成功要素 <a class="header-anchor" href="#成功要素" aria-label="Permalink to &quot;成功要素&quot;">​</a></h3><ul><li>品种多、库存大</li><li>管理层出色</li><li>关键管理者是股东——提成激励</li></ul><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="行业困境" tabindex="-1">行业困境 <a class="header-anchor" href="#行业困境" aria-label="Permalink to &quot;行业困境&quot;">​</a></h3><ul><li>保费增长仅3.1%</li><li>综合成本率109.1</li><li>&quot;纸包不住火&quot;</li></ul><h3 id="伯克希尔优势" tabindex="-1">伯克希尔优势 <a class="header-anchor" href="#伯克希尔优势" aria-label="Permalink to &quot;伯克希尔优势&quot;">​</a></h3><ul><li>浮存金成本概念</li><li>26年中21年成本低于国债</li><li>11年成本为负</li></ul><h3 id="超级巨灾保险" tabindex="-1">超级巨灾保险 <a class="header-anchor" href="#超级巨灾保险" aria-label="Permalink to &quot;超级巨灾保险&quot;">​</a></h3><ul><li>世界最大承保商</li><li>年保费约1亿美元</li><li>好年赚1亿，坏年亏2亿</li><li>1991年日本台风，承保利润约1100万</li></ul><h3 id="浮存金-1991" tabindex="-1">浮存金（1991） <a class="header-anchor" href="#浮存金-1991" aria-label="Permalink to &quot;浮存金（1991）&quot;">​</a></h3><ul><li>约19亿美元</li><li>资金成本极低</li></ul><hr><h2 id="可交易证券" tabindex="-1">可交易证券 <a class="header-anchor" href="#可交易证券" aria-label="Permalink to &quot;可交易证券&quot;">​</a></h2><h3 id="六大重仓" tabindex="-1">六大重仓 <a class="header-anchor" href="#六大重仓" aria-label="Permalink to &quot;六大重仓&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>市值(M)</th></tr></thead><tbody><tr><td>可口可乐</td><td>46,700,000股</td><td>3,747.7</td></tr><tr><td>GEICO</td><td>6,850,000股</td><td>1,363.2</td></tr><tr><td>首都城市/ABC</td><td>3,000,000股</td><td>1,300.5</td></tr><tr><td>吉列</td><td>12,000,000股</td><td>1,347.0</td></tr><tr><td>华盛顿邮报</td><td>1,727,765股</td><td>336.1</td></tr><tr><td>富国银行</td><td>5,000,000股</td><td>290.0</td></tr></tbody></table><h3 id="新投资-健力士" tabindex="-1">新投资：健力士 <a class="header-anchor" href="#新投资-健力士" aria-label="Permalink to &quot;新投资：健力士&quot;">​</a></h3><ul><li>第一次重仓海外公司</li><li>商业模式类似可口可乐</li></ul><hr><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><h3 id="凯恩斯语录" tabindex="-1">凯恩斯语录 <a class="header-anchor" href="#凯恩斯语录" aria-label="Permalink to &quot;凯恩斯语录&quot;">​</a></h3><blockquote><p>&quot;真正正确的投资方法，就是把相当大资金放到你懂、管理层你信任的企业。不要分散。&quot;</p></blockquote><h3 id="不分散的理由" tabindex="-1">不分散的理由 <a class="header-anchor" href="#不分散的理由" aria-label="Permalink to &quot;不分散的理由&quot;">​</a></h3><ul><li>好企业太少</li><li>不懂的买一堆不会对</li><li>已经找到几个，足够了</li></ul><hr><h2 id="错误-错过范妮梅" tabindex="-1">错误：错过范妮梅 <a class="header-anchor" href="#错误-错过范妮梅" aria-label="Permalink to &quot;错误：错过范妮梅&quot;">​</a></h2><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h3><ul><li>1988年初已理解公司</li><li>CEO戴维·马克斯韦尔做得很好</li><li>买了700万股后因价格涨了就停了</li></ul><h3 id="错误本质" tabindex="-1">错误本质 <a class="header-anchor" href="#错误本质" aria-label="Permalink to &quot;错误本质&quot;">​</a></h3><ul><li>不喜欢小仓位，所以没继续买</li><li>结果错过14亿美元</li><li>机会在面前没重仓就是错</li></ul><hr><h2 id="固定收益证券变动" tabindex="-1">固定收益证券变动 <a class="header-anchor" href="#固定收益证券变动" aria-label="Permalink to &quot;固定收益证券变动&quot;">​</a></h2><h3 id="出售" tabindex="-1">出售 <a class="header-anchor" href="#出售" aria-label="Permalink to &quot;出售&quot;">​</a></h3><ul><li>RJR纳贝斯克债券（获利1.5亿美元）</li></ul><h3 id="新购入" tabindex="-1">新购入 <a class="header-anchor" href="#新购入" aria-label="Permalink to &quot;新购入&quot;">​</a></h3><ul><li>美国运通优先股</li><li>纽约第一国民银行优先股</li></ul><h3 id="美国航空问题" tabindex="-1">美国航空问题 <a class="header-anchor" href="#美国航空问题" aria-label="Permalink to &quot;美国航空问题&quot;">​</a></h3><ul><li>行业全面亏损</li><li>破产公司低价竞争</li><li>投资减值</li><li>巴菲特承认：没看到航空业价格战激烈程度</li></ul><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于投资策略</strong>：</p><blockquote><p>&quot;真正正确的投资方法就是把相当大资金放到你懂、管理层你信任的企业，不要分散。&quot;</p></blockquote></li><li><p><strong>关于特许经营权</strong>：</p><blockquote><p>&quot;时间是好生意的朋友，坏生意的敌人。&quot;</p></blockquote></li><li><p><strong>关于错过机会</strong>：</p><blockquote><p>&quot;机会放在你面前你没重仓，就是错。&quot;</p></blockquote></li><li><p><strong>关于管理层</strong>：</p><blockquote><p>&quot;我们已经和喜欢欣赏的人做生意，为什么要换给不认识不喜欢的？&quot;</p></blockquote></li></ol><hr><h2 id="_1991年启示" tabindex="-1">1991年启示 <a class="header-anchor" href="#_1991年启示" aria-label="Permalink to &quot;1991年启示&quot;">​</a></h2><ol><li><strong>特许经营权价值</strong>：有护城河的企业才能持续创造价值</li><li><strong>集中投资</strong>：找到好企业就重仓，不要分散</li><li><strong>规模是业绩敌人</strong>：越大越难找到影响整体的机会</li><li><strong>错过机会的代价</strong>：比做错事伤害更大</li><li><strong>行业变迁</strong>：媒体行业特许经营权下降，需要重新评估</li></ol>',77)])])}const b=l(r,[["render",o]]);export{c as __pageData,b as default};
